1	/**
2	 * AI Flow Builder Router
3	 * Takes a natural language description and generates a workflow (nodes + connections).
4	 * Uses structured output to ensure reliable JSON generation.
5	 */
6	
7	import { z } from "zod";
8	import { router, organizationProcedure } from "../trpc";
9	import { generateText } from "ai";
10	import { createOpenAI } from "@ai-sdk/openai";
11	import { createAnthropic } from "@ai-sdk/anthropic";
12	import { createGoogleGenerativeAI } from "@ai-sdk/google";
13	import { db } from "@/db/db";
14	import { credentials } from "@/db/schema";
15	import { eq } from "drizzle-orm";
16	import { decryptObject } from "@/lib/encryption";
17	
18	const SYSTEM_PROMPT = `You are a workflow builder AI for Typeflow, an n8n-like workflow automation platform.
19	You receive a natural language description and generate a workflow as JSON.
20	
21	## Available Node Types
22	
23	### Triggers (every workflow needs exactly one)
24	- "webhook" - Receives HTTP requests. Config: {}
25	- "manualTrigger" - Manual execution. Config: {}
26	- "scheduleTrigger" - Runs on schedule. Config: { cronExpression: string }
27	- "chatTrigger" - Chat interface. Config: { welcomeMessage?: string }
28	
29	### AI Nodes
30	- "openai" - OpenAI GPT models. Config: { model: "gpt-4o"|"gpt-4o-mini", systemPrompt: string, userPrompt: string, temperature?: number }
31	- "anthropic" - Anthropic Claude models. Config: { model: "claude-sonnet-4-20250514", systemPrompt: string, userPrompt: string }
32	- "llmChain" - Unified multi-provider LLM. Config: { provider: "openai"|"anthropic"|"google", model: string, systemPrompt: string, userPrompt: string }
33	- "aiAgent" - AI Agent with tool use. Config: { provider: "openai"|"anthropic", model: string, systemPrompt: string, userPrompt: string, enableHttpTool?: boolean, enableCodeTool?: boolean, memoryType?: "none"|"buffer"|"postgres" }
34	- "textClassifier" - Classify text into categories. Config: { textField: string, categories: [{name: string, description: string}] }
35	- "infoExtractor" - Extract structured data. Config: { textField: string, schema: [{name: string, type: "string"|"number"|"boolean", description: string}] }
36	- "aiSummarize" - Summarize text. Config: { textField: string, strategy: "stuff"|"mapReduce", maxLength?: number }
37	- "guardrails" - Content safety checks. Config: { textField: string, checks: { pii?: boolean, jailbreak?: boolean, nsfw?: boolean, keywords?: string[] } }
38	
39	### RAG Pipeline
40	- "textSplitter" - Split text into chunks. Config: { textField: string, strategy: "recursive"|"character", chunkSize?: number, chunkOverlap?: number }
41	- "embedding" - Generate embeddings. Config: { textField: string, provider: "openai", model: "text-embedding-3-small" }
42	- "vectorStore" - Store/query vectors. Config: { operation: "upsert"|"query", storeName: string, textField?: string, embeddingField?: string, queryField?: string, topK?: number }
43	- "qaChain" - RAG Q&A. Config: { provider: "openai", model: "gpt-4o-mini", vectorStoreName: string, queryField: string }
44	
45	### AI Engineering
46	- "promptTemplate" - Reusable prompt templates. Config: { templateName: string, operation: "render"|"renderAndCall", systemTemplate: string, userTemplate: string }
47	- "modelRouter" - Smart model selection. Config: { strategy: "cost"|"quality"|"cascade"|"complexity" }
48	- "llmEvaluator" - Evaluate AI output quality. Config: { outputField: "content", inputField: "input", passThreshold: number }
49	- "aiCache" - Cache LLM responses. Config: { operation: "auto"|"check"|"store", ttlSeconds: number }
50	- "semanticCompare" - Compare text similarity. Config: { textAField: string, textBField: string, similarityThreshold: number }
51	
52	### Data Processing
53	- "code" - Custom JavaScript. Config: { code: string }
54	- "httpRequest" - HTTP requests. Config: { url: string, method: "GET"|"POST"|"PUT"|"DELETE", headers?: object, body?: string }
55	- "filter" - Filter items. Config: { conditions: [{field: string, operator: "equals"|"contains"|"greaterThan", value: string}] }
56	- "if" - Conditional branching. Config: { branches: [{id: string, name: string, conditions: [{field: string, operator: string, value: string}]}], elseEnabled: true }
57	- "switch" - Multi-way branching. Config: { cases: [{id: string, name: string, conditions: [{field: string, operator: string, value: string}]}] }
58	- "editFields" - Transform fields. Config: { fields: [{name: string, value: string}], mode: "set" }
59	- "merge" - Merge data streams. Config: {}
60	
61	### Other
62	- "wait" - Delay execution. Config: { seconds: number }
63	- "noop" - No operation (passthrough). Config: {}
64	
65	## Rules
66	1. Every workflow needs EXACTLY ONE trigger node as the first node.
67	2. Use "{{ $json.fieldName }}" syntax in prompts to reference input data.
68	3. Connect nodes logically - output of one feeds input of next.
69	4. Position nodes top-to-bottom with ~150px vertical spacing between rows.
70	5. Start trigger at position { x: 400, y: 50 }.
71	6. For AI nodes that need credentials, leave credentialId empty (user will configure later).
72	7. Generate unique IDs for nodes (use simple format like "node_1", "node_2", etc).
73	8. Keep configs minimal - only include fields that are needed.
74	
75	## Output Format
76	Return ONLY a JSON object with this structure:
77	{
78	  "nodes": [
79	    { "id": "node_1", "type": "webhook", "label": "Webhook", "position": {"x": 400, "y": 50}, "config": {} }
80	  ],
81	  "connections": [
82	    { "sourceId": "node_1", "targetId": "node_2" }
83	  ],
84	  "description": "Brief description of what this workflow does"
85	}`;
86	
87	async function getModelForGeneration(organizationId: string) {
88	  // Try to find any AI credential (prefer OpenAI, then Anthropic, then Google)
89	  const creds = await db.query.credentials.findMany({
90	    where: eq(credentials.organizationId, organizationId),
91	  });
92	
93	  for (const providerType of ["openai", "anthropic", "google"]) {
94	    const cred = creds.find(c => c.type === providerType);
95	    if (cred) {
96	      const config = decryptObject<{ apiKey: string; baseUrl?: string }>(cred.config as string);
97	      switch (providerType) {
98	        case "openai":
99	          return { model: createOpenAI({ apiKey: config.apiKey, baseURL: config.baseUrl })("gpt-4o-mini"), provider: "openai" };
100	        case "anthropic":
101	          return { model: createAnthropic({ apiKey: config.apiKey, baseURL: config.baseUrl })("claude-sonnet-4-20250514"), provider: "anthropic" };
102	        case "google":
103	          return { model: createGoogleGenerativeAI({ apiKey: config.apiKey, baseURL: config.baseUrl })("gemini-2.0-flash"), provider: "google" };
104	      }
105	    }
106	  }
107	
108	  throw new Error("No AI credentials found. Please add an OpenAI, Anthropic, or Google credential first.");
109	}
