3	import { useState, useRef, useEffect } from "react";
4	import { trpc } from "@/lib/trpc";
5	import { Button } from "@/components/ui/button";
6	import { Textarea } from "@/components/ui/textarea";
7	import { Bot, Send, Loader2, Sparkles, X, AlertCircle } from "lucide-react";
8	import type { Node, Edge } from "reactflow";
9	
10	interface AIFlowBuilderPanelProps {
11	  organizationId: string;
12	  onApplyFlow: (nodes: Node[], edges: Edge[]) => void;
13	  onClose: () => void;
14	}
15	
16	interface ChatMessage {
17	  role: "user" | "assistant";
18	  content: string;
19	  flow?: {
20	    nodes: Array<{ id: string; type: string; label: string; position: { x: number; y: number }; config: Record<string, unknown> }>;
21	    connections: Array<{ sourceId: string; targetId: string; sourceHandle?: string; targetHandle?: string }>;
22	    description: string;
23	  };
24	}
25	
26	export function AIFlowBuilderPanel({ organizationId, onApplyFlow, onClose }: AIFlowBuilderPanelProps) {
27	  const [messages, setMessages] = useState<ChatMessage[]>([
28	    {
29	      role: "assistant",
30	      content: "Describe the workflow you want to build. For example:\n\n- \"Webhook that receives customer emails, classifies them, and generates a reply for complaints\"\n- \"Chatbot that answers questions about our documentation\"\n- \"Pipeline that summarizes texts and evaluates the quality\"",
31	    },
32	  ]);
33	  const [input, setInput] = useState("");
34	  const [isGenerating, setIsGenerating] = useState(false);
35	  const messagesEndRef = useRef<HTMLDivElement>(null);
36	
37	  const generateFlowMutation = trpc.aiFlowBuilder.generateFlow.useMutation();
38	
39	  useEffect(() => {
40	    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
41	  }, [messages]);
42	
43	  const handleSubmit = async () => {
44	    if (!input.trim() || isGenerating) return;
45	
46	    const userMessage = input.trim();
47	    setInput("");
48	    setMessages(prev => [...prev, { role: "user", content: userMessage }]);
49	    setIsGenerating(true);
50	
51	    try {
52	      const result = await generateFlowMutation.mutateAsync({
53	        organizationId,
54	        prompt: userMessage,
55	      });
56	
57	      setMessages(prev => [
58	        ...prev,
59	        {
60	          role: "assistant",
61	          content: `Workflow created: **${result.description}**\n\n${result.nodes.length} nodes, ${result.connections.length} connections`,
62	          flow: result,
63	        },
64	      ]);
65	    } catch (error) {
66	      setMessages(prev => [
67	        ...prev,
68	        {
69	          role: "assistant",
70	          content: `Error: ${error instanceof Error ? error.message : "Failed to generate workflow"}`,
71	        },
72	      ]);
73	    } finally {
74	      setIsGenerating(false);
75	    }
76	  };
77	
78	  const handleApplyFlow = (flow: ChatMessage["flow"]) => {
79	    if (!flow) return;
80	
81	    // Convert to ReactFlow nodes
82	    const rfNodes: Node[] = flow.nodes.map(node => ({
83	      id: node.id,
84	      type: node.type,
85	      position: node.position,
86	      data: {
87	        label: node.label,
88	        config: node.config,
89	      },
90	    }));
91	
92	    // Convert to ReactFlow edges
93	    const rfEdges: Edge[] = flow.connections.map((conn, i) => ({
94	      id: `e-${conn.sourceId}-${conn.targetId}-${i}`,
95	      source: conn.sourceId,
96	      target: conn.targetId,
97	      sourceHandle: conn.sourceHandle || null,
98	      targetHandle: conn.targetHandle || null,
99	      type: "deletable",
100	    }));
101	
102	    onApplyFlow(rfNodes, rfEdges);
103	
104	    setMessages(prev => [
105	      ...prev,
106	      { role: "assistant", content: "Workflow has been added to the editor. You can now configure the nodes (credentials, prompts, etc.)." },
107	    ]);
108	  };
109	
110	  return (
111	    <div className="flex flex-col h-full bg-background border-l w-[400px]">
112	      {/* Header */}
113	      <div className="flex items-center justify-between px-4 py-3 border-b">
114	        <div className="flex items-center gap-2">
115	          <Sparkles className="h-4 w-4 text-slate-600" />
116	          <span className="font-semibold text-sm">AI Flow Builder</span>
117	        </div>
118	        <Button variant="ghost" size="sm" onClick={onClose} className="h-7 w-7 p-0">
119	          <X className="h-4 w-4" />
120	        </Button>
121	      </div>
122	
123	      {/* Messages */}
124	      <div className="flex-1 overflow-y-auto px-4 py-3 space-y-4">
125	        {messages.map((msg, i) => (
126	          <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
127	            <div className={`max-w-[90%] rounded-lg px-3 py-2 text-sm ${
128	              msg.role === "user"
129	                ? "bg-primary text-primary-foreground"
130	                : "bg-muted"
131	            }`}>
132	              <div className="whitespace-pre-wrap">{msg.content}</div>
133	
134	              {/* Show apply button for generated flows */}
135	              {msg.flow && (
136	                <div className="mt-3 space-y-2">
137	                  <div className="flex flex-wrap gap-1">
138	                    {msg.flow.nodes.map(node => (
139	                      <span key={node.id} className="inline-flex items-center px-2 py-0.5 rounded-full bg-background/50 text-xs font-medium">
140	                        {node.label}
141	                      </span>
142	                    ))}
143	                  </div>
144	                  <Button
145	                    size="sm"
146	                    className="w-full"
147	                    onClick={() => handleApplyFlow(msg.flow)}
148	                  >
149	                    <Sparkles className="h-3 w-3 mr-1" />
150	                    Apply to Editor
151	                  </Button>
152	                </div>
153	              )}
154	            </div>
155	          </div>
156	        ))}
157	
158	        {isGenerating && (
159	          <div className="flex justify-start">
160	            <div className="bg-muted rounded-lg px-3 py-2 text-sm flex items-center gap-2">
161	              <Loader2 className="h-3 w-3 animate-spin" />
162	              Generating workflow...
163	            </div>
164	          </div>
165	        )}
166	
167	        <div ref={messagesEndRef} />
168	      </div>
169	
170	      {/* Input */}
171	      <div className="border-t px-4 py-3">
172	        <div className="flex gap-2">
173	          <Textarea
174	            value={input}
175	            onChange={(e) => setInput(e.target.value)}
176	            placeholder="Describe your workflow..."
177	            className="resize-none text-sm"
178	            rows={2}
179	            onKeyDown={(e) => {
180	              if (e.key === "Enter" && !e.shiftKey) {
181	                e.preventDefault();
182	                handleSubmit();
183	              }
184	            }}
185	          />
186	          <Button
187	            size="sm"
188	            className="self-end px-3"
189	            onClick={handleSubmit}
190	            disabled={!input.trim() || isGenerating}
191	          >
192	            {isGenerating ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
193	          </Button>
194	        </div>
195	      </div>
196	    </div>
197	  );
198	}
